function google(q,tl){
  return new Promise((resolve,reject)=>{
    if(typeof q!=='string' || q.trim().length===0) resolve([]);
    q=encodeURIComponent(q);

    let url='http://translate.google.cn/translate_a/single?client=gtx&dt=t&ie=UTF-8&oe=UTF-8&sl=auto&tl='+tl+'&q='+q;
    http.get(url, function(res){
      if(res.statusCode!==200) resolve([]);
      let s=[],i=0;
      res.on('data',d=>{
        i+=d.length;
        s.push(d);
      });
      res.on('end',()=>{
        let r=Buffer.concat(s,i).toString('utf8');
        let j=JSON.parse(r);
        // console.debug(r)
        resolve({ [j[2]] : j[0].map(e=>e[0]).join() })
      });
    }).on('error',e=>resolve([]));
  });
}

function googles(q,tl='zh-CN'){
  function vq(a,uq="426928.3386708673") {
      if (null !== uq)
          var b = uq;
      else {
          b = sq('T');
          var c = sq('K');
          b = [b(), c()];
          b = (uq = window[b.join(c())] || "") || ""
      }
      var d = sq('t');
      c = sq('k');
      d = [d(), c()];
      c = "&" + d.join("") + "=";
      d = b.split(".");
      b = Number(d[0]) || 0;
      for (var e = [], f = 0, g = 0; g < a.length; g++) {
          var l = a.charCodeAt(g);
          128 > l ? e[f++] = l : (2048 > l ? e[f++] = l >> 6 | 192 : (55296 == (l & 64512) && g + 1 < a.length && 56320 == (a.charCodeAt(g + 1) & 64512) ? (l = 65536 + ((l & 1023) << 10) + (a.charCodeAt(++g) & 1023),
          e[f++] = l >> 18 | 240,
          e[f++] = l >> 12 & 63 | 128) : e[f++] = l >> 12 | 224,
          e[f++] = l >> 6 & 63 | 128),
          e[f++] = l & 63 | 128)
      }
      a = b;
      for (f = 0; f < e.length; f++)
          a += e[f],
          a = tq(a, "+-a^+6");
      a = tq(a, "+-3^+b+-f");
      a ^= Number(d[1]) || 0;
      0 > a && (a = (a & 2147483647) + 2147483648);
      a %= 1000000;
      return c + (a.toString() + "." + (a ^ b))
  };
  function sq(a) {
      return function() {
          return a
      }
  }
  function tq(a, b) {
      for (var c = 0; c < b.length - 2; c += 3) {
          var d = b.charAt(c + 2);
          d = "a" <= d ? d.charCodeAt(0) - 87 : Number(d);
          d = "+" == b.charAt(c + 1) ? a >>> d : a << d;
          a = "+" == b.charAt(c) ? a + d & 4294967295 : a ^ d
      }
      return a
  }
  return new Promise((resolve,reject)=>{
    if(typeof q!=='string' || q.trim().length===0) resolve([]);
    let tk=vq(q);
    q='&q='+encodeURIComponent(q);
    let url='https://translate.google.cn/translate_a/single?client=t&sl=auto&tl='+tl+'&hl=zh-CN&dt=at&dt=bd&dt=ex&dt=ld&dt=md&dt=qca&dt=rw&dt=rm&dt=ss&dt=t&ie=UTF-8&oe=UTF-8&otf=2&ssel=0&tsel=0&kc=1'+tk+q;
    https.get(url, res=>{
      if(res.statusCode!==200) resolve([]);
      let s=[],i=0;
      res.on('data',d=>{
        i+=d.length;
        s.push(d);
      });
      res.on('end',()=>{
        let r=Buffer.concat(s,i).toString('utf8');
        let j=JSON.parse(r);
        resolve({ [j[2]] : j[0]&&j[0].map(e=>e[0]).join('') });
      });
    }).on('error', ()=>resolve([]));
  });
};




