function daum(q,tl) {
  function lang(l) {
    if(typeof l==='string') l=l.toLowerCase();
    switch(l) {
      case 'en':
      case 'eng':
      case 'english':
        return 'eng'
      case 'jp':
      case 'jpn':
      case 'japan':
        return 'jpn';
      case 'chn':
      case 'chinese':
      case 'china':
      case 'zh-cn':
      case 'cn':
      case 'ch':
        return 'chn';
      case 'hanja':
        return 'hanja';
      case 'fr':
      case 'french':
        return 'fr';
      case 'ko':
      case 'kor':
      case 'korea':
      default:
        return 'kor';
    }
  }
  return new Promise((resolve,reject)=>{
    if(!q) return resolve(null);
    let url='http://suggest-bar.daum.net/suggest?mod=json&code=utf_in_out&enc=utf&id=language&cate='+lang(tl)+'&q='+encodeURIComponent(q);
    http.get(url, function(res){
      if(res.statusCode!==200) resolve([]);
      let s=[],i=0;
      res.on('data',d=>{
        i+=d.length;
        s.push(d);
      });
      res.on('end',()=>{
        let r=Buffer.concat(s,i).toString('utf8');
        let j=JSON.parse(r);
        // j.slice(1).forEach(e=>console.log('---',e));
        r=j.items.map(e=>{
          let row=e.split('|');
          return {s:row[1],t:row[2]};
        });
        r=[] .concat(...r);
        resolve(r)
      });  
    });
  });
}


