function hanja(q) {
  return new Promise((resolve,reject)=>{
    if(!q) return resolve(null);
    let url='http://alldic.daum.net/search.do?mod=json&dic=hanja&q='+encodeURIComponent(q);
    http.get(url, function(res){
      if(res.statusCode!==200) resolve([]);
      let s=[],i=0;
      res.on('data',d=>{
        i+=d.length;
        s.push(d);
      });
      res.on('end',()=>{
        let r=Buffer.concat(s,i).toString('utf8');
        let cheerio=require('cheerio');
        let $=cheerio.load(r);

        r=[];

        {
          let ja=$.root().find('.hanja_box');
          let res={
            hanja:[],
            example:[]
          };

          ja.find('.search_word').each((i,e)=>{
            let hanja=$(e).text().replace(/([\t\n ])+/g,' ').trim();
            res.hanja[i]=[];
            res.hanja[i].push(hanja.slice(0,1), hanja.slice(2))
          });
          // res.hanjas=hanjas;

          ja.find('.list_search').each(function(i,e){
            let spans=[];
            $(e).find('li').each((i,li)=>{
              let span=$(li).find('span:nth-child(2)').text();
              spans.push(span);
            });
            res.hanja[i].push(...spans);
          });

          $.root().find('.kokk_type').each((i,e)=>{
            let k=$(e).find('.tit_searchword a').map((i,e)=>$(e).text()).toArray();
            let d=$(e).find('.txt_search').text().trim()
            k.push(d);
            res.example.push(k)
          });
          resolve(res)
        }
      });  
    });
  });
}

